B1 =  Ts*wp0*wp1*wp2*(3*Ts**2*wz1*wz2 + 2*Ts*wz1 + 2*Ts*wz2 - 4)/(2*wz1*wz2*(Ts*wp1 + 2)*(Ts*wp2 + 2))
B0 =  Ts*wp0*wp1*wp2*(Ts*wz1 + 2)*(Ts*wz2 + 2)/(2*wz1*wz2*(Ts*wp1 + 2)*(Ts*wp2 + 2))
A3 =  (Ts*wp1 - 2)*(Ts*wp2 - 2)/((Ts*wp1 + 2)*(Ts*wp2 + 2))
